package com.ipartek.formacion.ejemplos.tiendajakarta.pruebas;

import java.util.Set;

import com.ipartek.formacion.ejemplos.tiendajakarta.accesodatos.DaoRol;
import com.ipartek.formacion.ejemplos.tiendajakarta.accesodatos.DaoUsuario;
import com.ipartek.formacion.ejemplos.tiendajakarta.modelos.Rol;
import com.ipartek.formacion.ejemplos.tiendajakarta.modelos.Usuario;

import bibliotecas.fabrica.Fabrica;
import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;

public class DaoRolJpaPruebas {
	public static void main(String[] args) {
		DaoRol dao = (DaoRol) Fabrica.getObjeto("dao.rol");

		dao.insertar(Rol.builder().nombre("ADMINISTRADOR").build());
		dao.insertar(Rol.builder().nombre("USUARIO").build());
		dao.insertar(Rol.builder().nombre("Prueba3").descripcion("La prueba 3").build());

		Rol rol4 = Rol.builder().nombre(
//				"Prueba4ñalsdkfjñlaskdjgñlkhasdñlfkjañsdlkghñlaskdjfñlakhsdñlgkjañsldkfhñlaskdjgñlkahsdñflkjasdg")
				"Prueba4").descripcion(
//						"")
						"Descripción 4")
				.build();

		ValidatorFactory factory = Validation.buildDefaultValidatorFactory();
		Validator validator = factory.getValidator();

		Set<ConstraintViolation<Rol>> errores = validator.validate(rol4);

		for (ConstraintViolation<Rol> error : errores) {
			System.out.printf("%s: %s\n", error.getPropertyPath(), error.getMessage());
		}

		if (errores.size() == 0) {
			for (Rol rol : dao.obtenerTodos()) {
				System.out.println(rol);
			}
		}

		DaoUsuario daoUsuario = (DaoUsuario) Fabrica.getObjeto("dao.usuario");

		daoUsuario.insertar(Usuario.builder().nombre("Javier").email("javier@email.net").password("javier")
				.rol(Rol.builder().id(1L).build()).build());
		daoUsuario.insertar(Usuario.builder().nombre("Pepe").email("pepe@email.net").password("pepe")
				.rol(Rol.builder().id(2L).build()).build());
		daoUsuario.insertar(Usuario.builder().nombre("Juan").email("juan@email.net").password("juan")
				.rol(Rol.builder().id(2L).build()).build());

		for(Usuario usuario: daoUsuario.obtenerTodos()) {
			System.out.println(usuario);
		}
		
	}
}
